// Postpartum (hemorrhage, physiology, care)

export const ragEntriesMid = [

  // === Safety & Medication Deep Dive (IDs 581–636) ===
  { id: 581, category: 'treatment', keywords: ['cbt and medication', 'combining treatments depression'], question: "Should I do therapy and medication together?", response: "A lot of women do best with both. Medication helps balance the brain chemistry while therapy (like CBT) gives you practical tools to handle thoughts and feelings. They work really well together — many women feel steadier faster this way." },
  { id: 582, category: 'treatment', keywords: ['bright light therapy', 'exercise for depression'], question: "Are there other things that help besides medicine?", response: "Yes — regular exercise, bright light therapy (especially in the morning), good sleep, and cutting back on alcohol can all make a real difference. They're not a replacement for medicine or therapy, but they support everything else you're doing." },
  { id: 583, category: 'treatment', keywords: ['tms ect ketamine depression'], question: "What if regular treatments still don't help?", response: "There are other options like transcranial magnetic stimulation (TMS), esketamine, or (in very severe cases) electroconvulsive therapy (ECT). These are usually done under specialist care. Your doctor can talk through whether one of these might be right for you." },
  { id: 584, category: 'safety', keywords: ['stopping antidepressants safely', 'antidepressant withdrawal'], question: "How do I stop an antidepressant safely?", response: "Never stop suddenly — it can cause withdrawal symptoms like dizziness, nausea, or mood changes. Your doctor will help you taper slowly over weeks. That makes the process much smoother and safer." },
  { id: 585, category: 'safety', keywords: ['antidepressant interactions', 'other medicines with antidepressants'], question: "Do antidepressants interact with other medicines?", response: "They can, so it's important that every doctor and pharmacist knows all the medicines, supplements, and herbs you take (including St. John's wort). Bring a full list to every appointment so they can keep you safe." },
  { id: 586, category: 'treatment', keywords: ['how to choose antidepressant'], question: "How does my doctor choose which antidepressant to start?", response: "They look at your symptoms, any other health conditions, what has worked for you or your family in the past, and which side effects you want to avoid most (like weight gain or sexual side effects). It's a team decision." },
  { id: 587, category: 'safety', keywords: ['alcohol and antidepressants'], question: "Should I drink alcohol while on antidepressants?", response: "It's usually best to limit or avoid alcohol. It can make side effects worse, reduce how well the medicine works, and make depression or PMDD symptoms feel heavier. Cutting back often helps you feel steadier faster." },
  { id: 588, category: 'treatment', keywords: ['reminder for taking medicine', 'pill box antidepressants'], question: "Any tips for remembering to take my medicine?", response: "A weekly pill organizer and phone reminders can make a big difference. Some women link it to something they already do every day (like brushing teeth). Small habits like this help the medicine work its best." },

  // === Tricyclic Antidepressants (IDs 589–604) ===
  { id: 589, category: 'treatment', keywords: ['tricyclic antidepressants', 'tca', 'what are tcas'], question: "What are tricyclic antidepressants (TCAs)?", response: "TCAs are an older group of medicines that can help with depression, anxiety, and certain kinds of pain (like nerve pain, fibromyalgia, or migraines). They work by balancing brain chemicals, but they're usually not the first choice anymore because newer medicines tend to have fewer side effects." },
  { id: 590, category: 'treatment', keywords: ['common tcas', 'nortriptyline', 'amitriptyline', 'desipramine'], question: "What are the most common TCAs?", response: "The ones doctors use most often are nortriptyline (Pamelor), amitriptyline (Elavil), and desipramine (Norpramin). They're often taken at bedtime because they can make you sleepy, which can actually be helpful if you're having trouble sleeping." },
  { id: 591, category: 'treatment', keywords: ['how do tcas work for pain', 'tca for nerve pain'], question: "How do TCAs help with pain?", response: "For pain conditions like nerve pain or fibromyalgia, TCAs calm overactive nerve signals. The dose used for pain is usually much lower than the dose used for depression, so side effects tend to be milder." },
  { id: 592, category: 'treatment', keywords: ['tca side effects', 'common side effects of tcas'], question: "What are the common side effects of TCAs?", response: "The most frequent ones are dry mouth, constipation, drowsiness, dizziness when standing up, weight gain, and sometimes changes in sex drive. Most are mild and often improve after the first couple of weeks as your body adjusts." },
  { id: 593, category: 'treatment', keywords: ['serious side effects tca', 'tca overdose'], question: "Are there serious side effects with TCAs?", response: "Yes — they can cause heart rhythm problems, seizures, severe constipation, or trouble urinating. If you get chest pain, fast/irregular heartbeat, severe dizziness, vomiting that won't stop, or you feel like you took too many pills, call 911 or go to the ER right away." },
  { id: 594, category: 'treatment', keywords: ['who should not take tcas', 'tca contraindications'], question: "Who should not take TCAs?", response: "TCAs are usually avoided in people with certain heart conditions, seizures, or a high risk of suicide (they can be dangerous if someone takes too many). Older adults are more sensitive to side effects too. Your doctor will check your health history before prescribing one." },
  { id: 595, category: 'treatment', keywords: ['how long until tca works'], question: "How long until a TCA starts working?", response: "For depression or anxiety it usually takes 2–6 weeks to feel the full benefit. For pain relief some people notice improvement in a week or two. Your doctor will start with a low dose and slowly increase it if needed." },
  { id: 596, category: 'treatment', keywords: ['how long to stay on tca'], question: "How long do I need to stay on a TCA?", response: "If it's helping your depression or PMDD, most people stay on it for at least 6–9 months after they feel better — sometimes a year or longer if symptoms have been severe or recurrent. Never stop suddenly; your doctor will help you taper safely." },
  { id: 597, category: 'treatment', keywords: ['stopping tca safely', 'tca withdrawal'], question: "How do I stop a TCA safely?", response: "You should never stop a TCA suddenly — it can cause headache, nausea, dizziness, or mood changes. Your doctor will give you a slow tapering plan over weeks so you feel as steady as possible." },
  { id: 598, category: 'treatment', keywords: ['tca and pregnancy', 'tca breastfeeding'], question: "Can I take a TCA if I'm pregnant or breastfeeding?", response: "Some TCAs are considered safer than others during pregnancy and breastfeeding, but untreated depression also carries risks. Talk openly with your doctor so you can weigh the options together and choose the safest plan for you and your baby." },
  { id: 599, category: 'treatment', keywords: ['tca interactions', 'other medicines with tcas'], question: "Do TCAs interact with other medicines?", response: "They can, especially with certain heart medicines, other antidepressants, or herbs like St. John's wort. Always give every doctor and pharmacist a full list of everything you take so they can keep you safe." },
  { id: 600, category: 'treatment', keywords: ['tca and alcohol'], question: "Should I drink alcohol while taking a TCA?", response: "It's best to limit or avoid alcohol. It can make drowsiness, dizziness, and other side effects much stronger and can also reduce how well the medicine works." },
  { id: 601, category: 'treatment', keywords: ['tca dosing', 'taking tca at night'], question: "When should I take my TCA?", response: "Most people take it once a day at bedtime because it can make you sleepy. That can actually be helpful if you're having trouble sleeping from depression or PMDD." },
  { id: 602, category: 'treatment', keywords: ['tca for pmdd'], question: "Can TCAs be used for PMDD?", response: "They're not usually the first choice anymore, but some women with severe symptoms that haven't responded to SSRIs or birth control find them helpful. Your doctor would only consider one after other options haven't worked well enough." },
  { id: 603, category: 'safety', keywords: ['tca overdose risk'], question: "Are TCAs dangerous if I take too many?", response: "Unfortunately yes — TCAs can be very dangerous in overdose. That's why they're prescribed with extra caution if someone has thoughts of self-harm. If you ever feel unsafe, please reach out right away to 988 or your doctor." },
  { id: 604, category: 'treatment', keywords: ['tca reminder tips'], question: "Any tips for remembering to take my TCA?", response: "A weekly pill organizer and setting a phone reminder at bedtime works well for most women. Linking it to brushing your teeth or another nightly habit makes it easier to stay consistent." },

  // === MAOIs (IDs 605–620) ===
  { id: 605, category: 'treatment', keywords: ['maoi', 'monoamine oxidase inhibitor', 'what is maoi'], question: "What are MAOIs?", response: "MAOIs are an older type of antidepressant that can be very effective for severe depression or anxiety when other medicines haven't helped enough. They work by raising certain brain chemicals that affect mood. They need careful diet and medicine rules, but they can be a good option for some women." },
  { id: 606, category: 'treatment', keywords: ['common maois', 'phenelzine', 'tranylcypromine', 'selegiline patch'], question: "What are the most common MAOIs?", response: "The ones doctors use most often are phenelzine (Nardil), isocarboxazid (Marplan), tranylcypromine (Parnate), and selegiline (Emsam patch). The patch form usually has fewer diet restrictions than the pills." },
  { id: 607, category: 'treatment', keywords: ['maoi diet', 'tyramine foods', 'low tyramine diet'], question: "Do I have to follow a special diet on an MAOI?", response: "Yes — you need to avoid foods high in tyramine (aged cheeses, cured meats, draft beer, overly ripe or fermented foods) because they can cause a dangerous spike in blood pressure. Your doctor will give you a full safe-food list." },
  { id: 608, category: 'safety', keywords: ['maoi interactions', 'serotonin syndrome maoi'], question: "Are there medicines I can't take with an MAOI?", response: "Yes — MAOIs can interact dangerously with many other antidepressants, pain medicines, cold medicines, and even some herbs. Combining them can cause serotonin syndrome, which is a medical emergency. Always tell every doctor and pharmacist you're on an MAOI." },
  { id: 609, category: 'safety', keywords: ['maoi side effects', 'common side effects maoi'], question: "What are the common side effects of MAOIs?", response: "The most frequent ones are headache, trouble sleeping, daytime drowsiness, dizziness when standing up, dry mouth, and changes in sex drive. Most are mild and often improve after the first few weeks." },
  { id: 610, category: 'safety', keywords: ['serious maoi side effects', 'hypertensive crisis'], question: "What are the serious risks with MAOIs?", response: "The biggest risks are dangerously high blood pressure (hypertensive crisis) from tyramine-rich foods or certain medicines, and serotonin syndrome. Symptoms like sudden severe headache, chest pain, fast heartbeat, confusion, or vomiting mean you need emergency help right away (call 911)." },
  { id: 611, category: 'treatment', keywords: ['who should not take maoi', 'maoi contraindications'], question: "Who should not take an MAOI?", response: "They're usually avoided if you can't follow the special diet, have certain heart or liver problems, seizures, are pregnant or breastfeeding, or are at high risk for suicide. Older adults are also more sensitive to side effects. Your doctor will check your history carefully first." },
  { id: 612, category: 'treatment', keywords: ['how long until maoi works'], question: "How long until an MAOI starts working?", response: "Like most antidepressants, you may start to notice some improvement in 2–4 weeks, but the full benefit can take 4–8 weeks or longer." },
  { id: 613, category: 'treatment', keywords: ['how long to stay on maoi'], question: "How long do I need to stay on an MAOI?", response: "If it's helping your severe depression or PMDD, most people stay on it for at least a year. Your doctor will work with you to decide the right length based on how you've responded and how many episodes you've had." },
  { id: 614, category: 'safety', keywords: ['stopping maoi safely'], question: "How do I stop an MAOI safely?", response: "Never stop suddenly. Your doctor will give you a slow tapering plan. You'll also need to keep following the diet and medicine restrictions for at least 2 weeks after stopping before starting a new antidepressant." },
  { id: 615, category: 'safety', keywords: ['maoi and pregnancy'], question: "Can I take an MAOI if I'm pregnant or breastfeeding?", response: "MAOIs are generally not recommended during pregnancy or breastfeeding because of the risks. Talk openly with your doctor. They can help you find safer options." },
  { id: 616, category: 'safety', keywords: ['maoi and surgery'], question: "What if I need surgery while on an MAOI?", response: "Tell your surgeon and anesthesiologist well in advance. MAOIs can interact dangerously with anesthesia and pain medicines used during surgery. You may need to stop the MAOI weeks ahead under your doctor's guidance." },
  { id: 617, category: 'safety', keywords: ['medical alert maoi'], question: "Should I wear a medical alert for an MAOI?", response: "Yes — it's a good idea to wear a medical alert bracelet or carry a card that says you take an MAOI. In an emergency, medical staff need to know so they don't give you something that could cause a dangerous interaction." },
  { id: 618, category: 'safety', keywords: ['maoi overdose'], question: "Are MAOIs dangerous in overdose?", response: "Unfortunately yes — they can be very dangerous if too many are taken. That's why they're prescribed with extra caution if someone has thoughts of self-harm. If you ever feel unsafe, please reach out right away to 988 or your doctor." },
  { id: 619, category: 'treatment', keywords: ['maoi reminder tips'], question: "Any tips for remembering to take my MAOI?", response: "A weekly pill organizer and a phone reminder at the same time every day work well for most women. Taking it with a consistent nightly habit (like brushing teeth) makes it easier to stay on track." },
  { id: 620, category: 'treatment', keywords: ['when to use maoi'], question: "When would a doctor prescribe an MAOI?", response: "Usually only when several other antidepressants haven't worked well enough for severe depression or anxiety. They're very effective for some people, but they require careful diet and medicine rules, so they're not the first choice." },

  // === Low-Tyramine Diet & MAOI Safety (IDs 621–636) ===
  { id: 621, category: 'safety', keywords: ['tyramine', 'what is tyramine'], question: "What is tyramine?", response: "Tyramine is a natural substance found in your body and in some foods — especially aged, cured, fermented, or overly ripe ones. It's harmless for most people, but when you're on an MAOI it can build up and cause problems if you eat too much of it." },
  { id: 622, category: 'safety', keywords: ['low tyramine diet', 'why low tyramine diet maoi'], question: "Why do I need a low-tyramine diet on an MAOI?", response: "MAOIs stop your body from breaking down tyramine the way it normally would. Too much tyramine can suddenly raise your blood pressure to dangerous levels. Following the diet keeps you safe while the medicine works." },
  { id: 623, category: 'safety', keywords: ['safe foods low tyramine', 'what can i eat on maoi diet'], question: "What foods are safe on a low-tyramine diet?", response: "Most fresh foods are fine: fresh fruits and vegetables, fresh meats, poultry, fish, eggs, grains, bread, rice, pasta, cottage cheese, mozzarella, and fresh milk products. Fresh is best — the fresher the food, the lower the tyramine." },
  { id: 624, category: 'safety', keywords: ['foods to avoid maoi', 'high tyramine foods'], question: "What foods should I avoid on a low-tyramine diet?", response: "Avoid aged cheeses, cured or smoked meats (salami, pepperoni, bacon), fermented foods (sauerkraut, kimchi, soy sauce, miso), overly ripe fruit, fava beans, draft beer, red wine, and sherry. Your doctor will give you the full list." },
  { id: 625, category: 'safety', keywords: ['maoi diet tips', 'leftovers maoi'], question: "Any easy tips for following the low-tyramine diet?", response: "Stick to fresh foods, eat leftovers the same day or freeze them right away, and check expiration dates. If you're ever unsure about a food, it's safer to skip it or ask your doctor." },
  { id: 626, category: 'safety', keywords: ['caffeine maoi', 'coffee on maoi'], question: "Can I have caffeine while on an MAOI?", response: "Most doctors recommend limiting or avoiding caffeine (coffee, tea, energy drinks) because it can add to the blood-pressure effects. Your doctor will tell you exactly how much is safe for you." },
  { id: 627, category: 'safety', keywords: ['stopping maoi diet', 'how long after stopping maoi'], question: "How long do I need to follow the low-tyramine diet after stopping an MAOI?", response: "You usually need to keep following the diet for at least 2 weeks after you stop the medicine. Your doctor will give you the exact timeline so you stay safe during the switch to a new treatment." },
  { id: 628, category: 'safety', keywords: ['hypertensive crisis symptoms', 'high blood pressure maoi'], question: "What are the warning signs of a tyramine reaction?", response: "Sudden severe headache, flushing, vomiting, chest pain, fast or irregular heartbeat, confusion, or feeling like you might pass out. These are emergencies — call 911 or go to the ER right away." },
  { id: 629, category: 'safety', keywords: ['accidentally ate tyramine food', 'what if i eat wrong food on maoi'], question: "What should I do if I accidentally eat a high-tyramine food?", response: "Don't panic, but call your doctor or nurse right away and tell them exactly what you ate. They'll tell you what to watch for and whether you need to be checked. It's always better to ask than to wait." },
  { id: 630, category: 'safety', keywords: ['medical alert maoi diet'], question: "Should I wear a medical alert for an MAOI?", response: "Yes — it's a really good idea. A bracelet or card that says you take an MAOI and need a low-tyramine diet lets emergency staff know right away in case something happens." },
  { id: 631, category: 'safety', keywords: ['maoi and surgery before', 'maoi before surgery'], question: "What if I need surgery while on an MAOI?", response: "Tell your surgeon and anesthesiologist as soon as you know about the procedure. MAOIs can interact with anesthesia and pain medicines, so you'll likely need to stop the medicine weeks ahead under your doctor's guidance." },
  { id: 632, category: 'treatment', keywords: ['selegiline patch diet'], question: "Do I still need the low-tyramine diet with the selegiline patch?", response: "At the lowest dose (6 mg per day) most people do not need the strict diet. At higher doses (9 or 12 mg) you do. Your doctor will tell you exactly what applies to your patch strength." },
  { id: 633, category: 'safety', keywords: ['maoi and alcohol'], question: "Can I drink alcohol on an MAOI?", response: "Draft beer, red wine, and sherry are high in tyramine and should be avoided. Most doctors recommend limiting or skipping alcohol completely while on an MAOI because it can make side effects stronger." },
  { id: 634, category: 'safety', keywords: ['pill box maoi', 'remembering maoi'], question: "Any tips for remembering to take my MAOI safely?", response: "A weekly pill organizer and a phone reminder at the same time every day work well. Taking it with a consistent nightly habit (like brushing your teeth) makes it easier to stay on track and remember the diet rules." },
  { id: 635, category: 'safety', keywords: ['maoi and other medicines'], question: "Why is it so important to tell every doctor I take an MAOI?", response: "Because MAOIs interact with many common medicines (cold medicines, pain relievers, other antidepressants, etc.). Giving every doctor and pharmacist a full list keeps you safe from dangerous interactions." },
  { id: 636, category: 'safety', keywords: ['maoi emergency signs'], question: "What should I do if I feel a tyramine reaction coming on?", response: "Stop eating, sit or lie down, and call 911 or go to the ER right away if you get a sudden severe headache, chest pain, fast heartbeat, vomiting, or feel like you might pass out. Quick action can prevent serious problems." },

  // === General Medication Side Effects & Safety (IDs 637–652) ===
  { id: 637, category: 'safety', keywords: ['what are side effects', 'medication side effects'], question: "What are side effects?", response: "Side effects are any unintended or unwanted reactions a medicine can cause. Most are mild and go away on their own, but some can be more serious. Every medicine has the potential for side effects, even over-the-counter ones and supplements." },
  { id: 638, category: 'safety', keywords: ['common side effects', 'mild side effects'], question: "What are some common mild side effects?", response: "The most frequent ones people notice are upset stomach, nausea, dry mouth, drowsiness, or a minor headache. They often fade after the first week or two as your body gets used to the medicine." },
  { id: 639, category: 'safety', keywords: ['serious side effects', 'dangerous side effects'], question: "When are side effects serious?", response: "Serious ones (though rare) can include severe bleeding, liver or kidney problems, heart issues, trouble breathing, or allergic reactions like swelling of the face or hives. If anything feels scary or sudden, get help right away." },
  { id: 640, category: 'safety', keywords: ['when to call doctor side effects', 'medication emergency'], question: "When should I call my doctor about side effects?", response: "Call your doctor or nurse right away for hives, rash, confusion, severe stomach pain, dark urine, yellow skin, or anything that worries you. Go to the ER or call 911 for chest pain, trouble breathing, swelling of the face/lips/tongue, seizures, or thoughts of harming yourself." },
  { id: 641, category: 'safety', keywords: ['how to prevent side effects', 'taking medicine safely'], question: "How can I lower my chance of side effects?", response: "Take the exact dose your doctor prescribed, tell them about every medicine and supplement you use, and never stop or change a dose without checking first. Starting low and going slow often helps your body adjust more gently." },
  { id: 642, category: 'safety', keywords: ['pill box reminder', 'remembering medicine'], question: "Any tips for remembering to take my medicine safely?", response: "A weekly pill organizer and a phone reminder at the same time every day work well for most women. Linking it to something you already do (like brushing your teeth) makes it much easier to stay consistent." },
  { id: 643, category: 'safety', keywords: ['drug interactions', 'mixing medicines'], question: "Why is it important to tell my doctor about all my medicines?", response: "Some medicines don't mix well and can cause serious interactions. Giving every doctor and pharmacist a full list (including vitamins, herbs, and over-the-counter stuff) helps keep you safe." },
  { id: 644, category: 'safety', keywords: ['side effects go away', 'body adjusting to medicine'], question: "Do side effects usually go away?", response: "Yes — many mild ones (like nausea or drowsiness) fade after the first week or two as your body adjusts. If anything sticks around or gets worse, tell your doctor so they can adjust the dose or try a different option." },
  { id: 645, category: 'safety', keywords: ['stopping medicine side effects', 'withdrawal from medicine'], question: "What happens if I stop a medicine suddenly?", response: "Some medicines can cause withdrawal symptoms (headache, nausea, dizziness, or mood changes) if stopped too quickly. Always talk to your doctor first — they'll help you taper safely." },
  { id: 646, category: 'safety', keywords: ['medication and pregnancy', 'side effects pregnancy'], question: "Are medicines safe during pregnancy?", response: "Some are safer than others. Untreated conditions like depression can also affect you and the baby, so it's important to talk openly with your doctor. Together you can choose the safest plan for you and your little one." },
  { id: 647, category: 'safety', keywords: ['acetaminophen limit', 'too much tylenol'], question: "How much acetaminophen is safe?", response: "Most adults should stay under 3000 mg total per day from all sources. Check the labels of every medicine you take — many cold remedies and pain relievers already contain it. Too much can harm your liver." },
  { id: 648, category: 'safety', keywords: ['sun sensitivity medicine', 'photosensitivity'], question: "Some medicines make my skin sensitive to the sun — what should I do?", response: "Stay in the shade, wear sunscreen, and cover up with clothing and a hat. It's a common side effect and easy to manage once you know to expect it." },
  { id: 649, category: 'safety', keywords: ['medication guide', 'fda medication guide'], question: "Where can I find more info about my medicine's side effects?", response: "Ask your doctor or pharmacist for the patient handout or the FDA Medication Guide that comes with the prescription. They're written in plain language and list the most important things to watch for." },
  { id: 650, category: 'safety', keywords: ['allergic reaction medicine', 'rash from medicine'], question: "What should I do if I get a rash or hives from a medicine?", response: "Stop the medicine and call your doctor or nurse right away. If the rash is around your eyes, lips, mouth, or genitals, or you have trouble breathing, go to the ER immediately — that could be an allergic reaction." },
  { id: 651, category: 'safety', keywords: ['constipation from medicine'], question: "My medicine is making me constipated — what helps?", response: "Eat more fruits, vegetables, and drink plenty of water. Gentle exercise and a mild laxative (if your doctor says it's okay) can also help. Let your doctor know so they can adjust the dose or add something to ease it." },
  { id: 652, category: 'safety', keywords: ['sexual side effects medicine'], question: "My medicine is affecting my sex drive — is that normal?", response: "It's a fairly common side effect with some antidepressants and other medicines. Don't be embarrassed to tell your doctor — they can often lower the dose, switch medicines, or add something that helps." },

  // === Serotonin Syndrome (IDs 653–668) ===
  { id: 653, category: 'safety', keywords: ['serotonin syndrome', 'what is serotonin syndrome'], question: "What is serotonin syndrome?", response: "Serotonin syndrome is a rare but serious condition that can happen when there's too much serotonin in the brain. It's usually caused by certain medicines or combinations of medicines. In rare cases it can become dangerous, so it's important to know the signs." },
  { id: 654, category: 'safety', keywords: ['serotonin syndrome symptoms', 'signs of serotonin syndrome'], question: "What are the symptoms of serotonin syndrome?", response: "Common signs include feeling anxious or restless, sweating, muscle spasms or twitching, shaking, fast heartbeat, fever, confusion, nausea, vomiting, or diarrhea. If you notice several of these after starting or changing a medicine, contact your doctor right away." },
  { id: 655, category: 'safety', keywords: ['what causes serotonin syndrome', 'medicines that cause serotonin syndrome'], question: "What causes serotonin syndrome?", response: "It can happen when you take medicines that raise serotonin levels — especially SSRIs, SNRIs, MAOIs, certain pain medicines, migraine treatments (triptans), St. John's wort, or even some cough medicines. Combining them or taking a new one too soon after stopping another can trigger it." },
  { id: 656, category: 'safety', keywords: ['serotonin syndrome emergency', 'when to go to ER'], question: "When is serotonin syndrome an emergency?", response: "Go to the ER or call 911 right away if you have a high fever, seizures, chest pain, sudden changes in blood pressure or heart rate, severe confusion, or you feel like you might pass out. These can become life-threatening quickly." },
  { id: 657, category: 'safety', keywords: ['serotonin syndrome treatment'], question: "How is serotonin syndrome treated?", response: "The first step is usually stopping the medicine(s) that caused it. Your doctor will monitor your heart rate, blood pressure, and temperature and may give medicines to calm the symptoms or block extra serotonin. Most people improve once the offending medicine is stopped." },
  { id: 658, category: 'safety', keywords: ['prevent serotonin syndrome', 'how to avoid serotonin syndrome'], question: "How can I prevent serotonin syndrome?", response: "Always tell every doctor and pharmacist about all the medicines, supplements, and herbs you take. Never start a new medicine without checking for interactions, and don't combine antidepressants or other serotonin-raising drugs without your doctor's okay." },
  { id: 659, category: 'safety', keywords: ['maoi and ssri interaction', 'switching from maoi'], question: "Can I take an SSRI and an MAOI together?", response: "No — that combination is very dangerous and can cause serotonin syndrome. You usually need to wait at least 2 weeks (sometimes longer) after stopping one before starting the other. Your doctor will guide you through the safe switch." },
  { id: 660, category: 'safety', keywords: ['st johns wort serotonin syndrome'], question: "Is St. John's wort safe with antidepressants?", response: "St. John's wort can raise serotonin levels and cause serotonin syndrome when combined with many antidepressants. It's best to avoid it or talk to your doctor before using any herbal product." },
  { id: 661, category: 'safety', keywords: ['serotonin syndrome and pain medicine'], question: "Can pain medicines cause serotonin syndrome?", response: "Some can — especially tramadol, fentanyl, meperidine, or cyclobenzaprine when combined with antidepressants. Always check with your doctor or pharmacist before taking any new pain medicine." },
  { id: 662, category: 'safety', keywords: ['serotonin syndrome and migraine medicine'], question: "Can migraine medicines cause serotonin syndrome?", response: "Triptans (the medicines many people use for migraines) can raise serotonin. If you're already on an antidepressant, talk to your doctor before using a triptan so they can make sure it's safe for you." },
  { id: 663, category: 'safety', keywords: ['serotonin syndrome and cough medicine'], question: "Can cough medicine cause serotonin syndrome?", response: "Some cough medicines that contain dextromethorphan can raise serotonin. It's smart to check with your pharmacist before taking any cold or cough product if you're on an antidepressant." },
  { id: 664, category: 'safety', keywords: ['serotonin syndrome and street drugs'], question: "Can street drugs cause serotonin syndrome?", response: "Yes — ecstasy, cocaine, amphetamines, and some other recreational drugs can dramatically raise serotonin levels. Mixing them with antidepressants is especially dangerous." },
  { id: 665, category: 'safety', keywords: ['how soon does serotonin syndrome start'], question: "How quickly can serotonin syndrome start?", response: "It usually begins within hours of taking a new medicine, increasing a dose, or adding a new drug. That's why it's important to watch for symptoms whenever you start or change a medication." },
  { id: 666, category: 'safety', keywords: ['serotonin syndrome diagnosis'], question: "How do doctors diagnose serotonin syndrome?", response: "There isn't a single blood test. Doctors look at your symptoms, recent medicines, and do a physical exam (checking for muscle twitching, reflexes, etc.). Being honest about everything you've taken helps them figure it out quickly." },
  { id: 667, category: 'safety', keywords: ['serotonin syndrome and pmdd'], question: "Is serotonin syndrome more common in PMDD?", response: "Not necessarily, but because many women with PMDD take SSRIs or other serotonin medicines, it's important to know the signs. The risk is the same as for anyone else taking those medicines." },
  { id: 668, category: 'safety', keywords: ['talking to doctor about serotonin syndrome risk'], question: "Should I ask my doctor about serotonin syndrome risk?", response: "Yes — it's smart to ask whenever you start a new medicine or change doses. Your doctor can review your full list and make sure nothing you're taking could interact dangerously." },

  // === Depression During & After Pregnancy (IDs 669–684) ===
  { id: 669, category: 'postpartum', keywords: ['antenatal depression', 'depression during pregnancy'], question: "What is antenatal depression?", response: "Antenatal depression is depression that happens while you're pregnant. It's more than just normal pregnancy worries — it can make everyday tasks feel overwhelming and can affect how you eat, sleep, and care for yourself. It's common and very treatable." },
  { id: 670, category: 'postpartum', keywords: ['postpartum depression', 'depression after birth'], question: "What is postpartum depression?", response: "Postpartum depression is depression that starts after giving birth. It can make you feel sad, hopeless, anxious, or overwhelmed, and can make it hard to care for yourself or your baby. It's not your fault — it's a real medical condition and help is available." },
  { id: 671, category: 'postpartum', keywords: ['postpartum blues vs depression'], question: "What's the difference between postpartum blues and postpartum depression?", response: "Postpartum blues are mild, common mood swings that usually start a few days after birth and fade within 2 weeks. Postpartum depression is more intense, lasts longer than 2 weeks, and can make daily life feel much harder. If it feels heavier than the blues, it's worth talking to your doctor." },
  { id: 672, category: 'postpartum', keywords: ['symptoms of postpartum depression'], question: "What are the main symptoms of postpartum depression?", response: "You might feel sad, hopeless, or cranky most of the day, lose interest in things you used to enjoy, have trouble sleeping even when the baby sleeps, feel very tired, guilty, or overwhelmed, or have trouble bonding with your baby. Many women also feel anxious or irritable." },
  { id: 673, category: 'postpartum', keywords: ['risk factors postpartum depression'], question: "Who is more likely to get postpartum depression?", response: "You're at higher risk if you had depression before, have a family history of depression, are going through a lot of stress, or don't have much support. Pregnancy hormones can also play a big role. It can happen to anyone — it's not because you did anything wrong." },
  { id: 674, category: 'safety', keywords: ['suicidal thoughts postpartum', 'postpartum crisis'], question: "What should I do if I'm having thoughts of harming myself or my baby?", response: "Please reach out right away — you don't have to carry this alone. In the US or Canada call or text 988, tell your doctor it's an emergency, or go to the nearest ER. Help is there 24/7 and it can make a real difference." },
  { id: 675, category: 'treatment', keywords: ['treatment for postpartum depression', 'postpartum depression medicines'], question: "How is postpartum depression treated?", response: "The two main treatments are counseling (like CBT) and antidepressant medicines. Some women do best with both. There's also a newer medicine called zuranolone that's taken for 2 weeks specifically for postpartum depression. Your doctor will help choose what's safest for you." },
  { id: 676, category: 'treatment', keywords: ['antidepressants during pregnancy'], question: "Is it safe to take antidepressants while pregnant?", response: "Many antidepressants are considered safe during pregnancy, but some carry more risk than others. Untreated depression also has risks for you and the baby. Your doctor will talk through the options so you can make the choice that feels right for your situation." },
  { id: 677, category: 'treatment', keywords: ['antidepressants breastfeeding'], question: "Can I take antidepressants while breastfeeding?", response: "Yes — many antidepressants are considered safe while breastfeeding. Small amounts can pass into breast milk, but for most medicines the benefits of treating depression usually outweigh the risks. Your doctor can help pick the safest option for you and your baby." },
  { id: 678, category: 'treatment', keywords: ['zuranolone postpartum'], question: "What is zuranolone and is it used for postpartum depression?", response: "Zuranolone (Zurzuvae) is a newer pill taken for just 2 weeks that can help with postpartum depression. It's not used during pregnancy. Your doctor can tell you if it might be a good fit for your situation." },
  { id: 679, category: 'postpartum', keywords: ['self care postpartum depression'], question: "What can I do on my own to feel better with postpartum depression?", response: "Rest when you can, accept help from others, eat nourishing food, get outside for gentle walks, and talk to someone you trust. Small acts of self-care really add up and can make the other treatments work even better." },
  { id: 680, category: 'postpartum', keywords: ['preventing postpartum depression'], question: "Can postpartum depression be prevented?", response: "If you've had depression before, your doctor may recommend starting therapy or even a medicine right after birth to lower the chance of it coming back. Having support, good sleep when possible, and realistic expectations can also help." },
  { id: 681, category: 'postpartum', keywords: ['bonding with baby postpartum depression'], question: "Is it normal to feel disconnected from my baby with postpartum depression?", response: "Yes — many women with postpartum depression feel like they can't bond with their baby the way they expected. It doesn't mean you're a bad parent. Treatment usually helps these feelings lift so the connection can grow." },
  { id: 682, category: 'safety', keywords: ['postpartum depression partner'], question: "What if my partner seems to have postpartum depression?", response: "Encourage them to talk to their doctor or nurse. You can also reach out for help yourself if you're worried about their safety or the baby's. Partners can get depressed too, and early support makes a big difference." },
  { id: 683, category: 'postpartum', keywords: ['how long does postpartum depression last'], question: "How long does postpartum depression last?", response: "It varies — with treatment many women start feeling better within weeks, but it can take a few months for the full effect. Some need longer support. The important thing is to keep checking in with your doctor so they can adjust the plan as needed." },
  { id: 684, category: 'postpartum', keywords: ['postpartum depression support'], question: "Where can I find support for postpartum depression?", response: "Talk to your doctor or a mental-health professional, join a support group for new parents, or reach out to close friends and family. You're not alone — lots of women go through this and come out stronger on the other side." },

  // === Depression in Children & Teens (IDs 685–700) ===
  { id: 685, category: 'depression', keywords: ['depression in teens', 'teen depression', 'child depression'], question: "Can teenagers and kids get depression?", response: "Yes — depression isn't just an adult thing. Teens and even younger children can have it, and it can make school, friendships, and family life feel really hard. It's more than normal moodiness, and it's very treatable." },
  { id: 686, category: 'depression', keywords: ['symptoms of teen depression', 'how depression looks in kids'], question: "What does depression look like in teens and kids?", response: "They often seem irritable, grouchy, or angry instead of just sad. Other signs include losing interest in things they used to love, sleeping too much or too little, changes in appetite, low energy, feeling worthless or guilty, trouble concentrating, or risky behaviors." },
  { id: 687, category: 'depression', keywords: ['causes of teen depression'], question: "What causes depression in teenagers?", response: "It's usually a mix of brain chemistry, genetics, hormones (especially during puberty), stress at school or home, past trauma, or family history. In girls, the hormonal ups and downs of the menstrual cycle can sometimes make it feel worse." },
  { id: 688, category: 'safety', keywords: ['teen suicidal thoughts', 'child in crisis'], question: "My teen is talking about hurting themselves — what should I do?", response: "Please take it seriously and get help right away. Call or text 988 (US/Canada), bring them to the ER, or call their doctor and say it's an emergency. You're not overreacting — quick support can make a huge difference." },
  { id: 689, category: 'treatment', keywords: ['treatment for teen depression', 'therapy for kids'], question: "How is depression treated in teens and kids?", response: "The main treatments are counseling (like CBT) and, when needed, antidepressant medicines. Many teens do best with both. Your child's doctor will work with your family to create a plan that feels safe and helpful." },
  { id: 690, category: 'treatment', keywords: ['medication for teen depression'], question: "Are antidepressants safe for teenagers?", response: "Some are approved and well-studied for teens. Doctors start with the lowest dose and watch closely, especially for any changes in mood or thoughts of self-harm. Regular check-ins help keep everything safe." },
  { id: 691, category: 'treatment', keywords: ['how long until teen feels better'], question: "How long does it take for a teen to feel better from depression?", response: "Most start to notice improvement in 2–4 weeks with medicine or therapy, but the full benefit can take 6–8 weeks or longer. Be patient — healing takes time, and it's okay if progress feels slow." },
  { id: 692, category: 'depression', keywords: ['teen depression vs normal moodiness'], question: "Is it just normal teen moodiness or real depression?", response: "Normal moodiness comes and goes. Depression lasts longer, interferes with school/friends/family, and often includes loss of interest in things they used to enjoy. If it's been going on for more than two weeks, it's worth getting it checked." },
  { id: 693, category: 'treatment', keywords: ['cbt for teen depression'], question: "Does therapy help teenagers with depression?", response: "Yes — CBT is one of the most effective treatments for teens. It helps them understand their thoughts and learn practical ways to cope with stress, school pressure, and big feelings." },
  { id: 694, category: 'safety', keywords: ['risky behavior teen depression'], question: "My teen is acting out or taking risks — could it be depression?", response: "Sometimes yes. Depression in teens can show up as anger, fighting, skipping school, substance use, or risky behaviors instead of obvious sadness. It's a signal that they need extra support." },
  { id: 695, category: 'depression', keywords: ['depression in girls hormones'], question: "Can hormones make depression worse in teen girls?", response: "Absolutely. The hormonal swings of the menstrual cycle (especially in the luteal phase) can intensify mood symptoms in girls who are already prone to depression or PMDD. Tracking symptoms can help show the pattern." },
  { id: 696, category: 'treatment', keywords: ['family support teen depression'], question: "How can I support my teen with depression?", response: "Listen without judgment, help them get to appointments, encourage healthy routines (sleep, movement, meals), and remind them that this is treatable. Your steady presence means more than you know." },
  { id: 697, category: 'safety', keywords: ['teen depression and suicide risk'], question: "How serious is the risk of suicide in depressed teens?", response: "It's real and needs immediate attention. If your teen talks about death, not wanting to be here, or harming themselves, treat it as an emergency and get help right away (988 or ER)." },
  { id: 698, category: 'treatment', keywords: ['ect tms for teen depression'], question: "Are there other treatments if regular therapy and medicine aren't enough?", response: "In severe cases that don't respond to other treatments, doctors sometimes use transcranial magnetic stimulation (TMS) or, rarely, electroconvulsive therapy (ECT). These are done under specialist care and only after other options have been tried." },
  { id: 699, category: 'depression', keywords: ['how common is teen depression'], question: "How common is depression in teenagers?", response: "It's more common than many people realize. Many teens struggle with it, but with the right support and treatment most feel much better and go on to do well in life." },
  { id: 700, category: 'depression', keywords: ['talking to teen about depression'], question: "How do I talk to my teen about depression?", response: "Start with something simple like 'I've noticed you seem really down lately and I'm worried about you. I'm here and I want to help.' Listen more than you speak, and let them know it's okay to get professional support — it doesn't mean they're broken." },

  // === Non-Medication & Adjunctive Treatments for Depression (IDs 701–716) ===
  { id: 701, category: 'treatment', keywords: ['exercise for depression', 'working out helps depression'], question: "Does exercise really help with depression?", response: "Yes — regular movement is one of the most evidence-based things you can do to lift your mood. Even gentle walks or light strength training a few times a week can make a real difference. Consistency matters more than intensity." },
  { id: 702, category: 'treatment', keywords: ['starting exercise when depressed', 'low motivation exercise'], question: "How do I start exercising when I feel too depressed to move?", response: "Start tiny. Even a 5–10 minute walk around the block or gentle stretching counts. The hardest part is the first step — once you get going, many women notice they feel a little lighter afterward." },
  { id: 703, category: 'treatment', keywords: ['yoga for depression', 'tai chi depression'], question: "Do yoga or tai chi help depression?", response: "They can. Both combine gentle movement with breathing and focus, which calms the mind and body. Many women with PMDD or depression find them soothing during the luteal phase. Even short sessions a couple of times a week can help." },
  { id: 704, category: 'treatment', keywords: ['meditation relaxation depression'], question: "Is meditation or relaxation helpful for depression?", response: "Yes — simple meditation, deep breathing, or progressive muscle relaxation can lower anxiety and give your mind a break from heavy thoughts. There are free apps and short guided sessions that make it easy to start." },
  { id: 705, category: 'treatment', keywords: ['massage for depression'], question: "Can massage help with depression?", response: "It can. Massage reduces stress hormones and helps you feel cared for in your body. Even a short session once in a while can give you a mental reset, especially when you're feeling overwhelmed." },
  { id: 706, category: 'treatment', keywords: ['self help depression', 'online counseling depression'], question: "Are self-help activities useful for depression?", response: "They really can be. Online guided counseling, workbooks, support groups, or even smartphone apps designed for mood can give you tools between appointments. Many women find them helpful alongside other treatments." },
  { id: 707, category: 'treatment', keywords: ['bright light therapy depression'], question: "What is bright light therapy and does it help depression?", response: "It's sitting in front of a special bright lamp for 30–60 minutes each morning. It's especially useful for seasonal depression but can also help regular depression and PMDD. Ask your doctor if it might be worth trying." },
  { id: 708, category: 'treatment', keywords: ['supplemental treatments depression', 'adjunctive therapies depression'], question: "What are supplemental or adjunctive treatments for depression?", response: "They're extra things you do alongside medicine or therapy — like exercise, yoga, meditation, bright light, or self-help activities. They don't replace the main treatments but can make them work even better." },
  { id: 709, category: 'treatment', keywords: ['mild depression treatment'], question: "If my depression is mild, do I still need medicine or therapy?", response: "Not always. For mild depression, lifestyle changes, exercise, mind-body practices, or self-help tools are sometimes enough. Your doctor will help you decide based on how much it's affecting your daily life." },
  { id: 710, category: 'treatment', keywords: ['moderate severe depression treatment'], question: "What's the best approach for moderate or severe depression?", response: "Most women with moderate to severe depression do best with a combination of counseling and medicine. Adding exercise, yoga, or bright light therapy can give extra support. Your doctor will build a plan that feels right for you." },
  { id: 711, category: 'treatment', keywords: ['staying motivated depression treatment'], question: "How do I stay motivated when depression makes everything feel hard?", response: "Be kind to yourself — depression steals motivation, so start with the smallest possible step. Tell a friend or family member what you're trying so they can cheer you on. Small wins add up faster than you think." },
  { id: 712, category: 'treatment', keywords: ['group exercise depression'], question: "Is it better to exercise alone or with others?", response: "Many women find it easier to stick with it when they do it with others — a walking buddy, group class, or trainer can make a big difference in motivation and consistency." },
  { id: 713, category: 'treatment', keywords: ['bright light therapy how to use'], question: "How do I use bright light therapy?", response: "You sit in front of a special 10,000-lux light box for 30–60 minutes each morning while you eat breakfast or read. It's simple and non-invasive. Your doctor can recommend a good one and the right timing for you." },
  { id: 714, category: 'treatment', keywords: ['self help apps depression'], question: "Are there good apps for depression?", response: "Yes — there are several well-designed ones that guide you through CBT exercises, mood tracking, meditation, or daily check-ins. Your doctor or therapist can recommend ones that fit well with your treatment plan." },
  { id: 715, category: 'treatment', keywords: ['support groups depression'], question: "Do support groups help with depression?", response: "They can. Hearing other people share similar struggles and learning what helped them can make you feel less alone and give you practical ideas to try." },
  { id: 716, category: 'treatment', keywords: ['starting small depression treatment'], question: "I feel too depressed to start any new treatment — what should I do?", response: "That's completely understandable. Start with the tiniest step possible — even just opening an app for 5 minutes or texting one supportive person. You don't have to feel motivated to begin; you just have to begin." },

  // === Depression with Chronic Illness (IDs 717–732) ===
  { id: 717, category: 'depression', keywords: ['depression and chronic illness', 'depression with other health problems'], question: "Is depression common when you have other health problems?", response: "Yes — it's very common. People with heart disease, diabetes, stroke, COPD, arthritis, chronic pain, cancer, obesity, or Parkinson's often struggle with depression too. The two can feed each other, so it's important to treat both." },
  { id: 718, category: 'depression', keywords: ['why does illness cause depression'], question: "Why does having a chronic illness make depression more likely?", response: "Living with ongoing pain, fatigue, limitations, fear of complications, or the daily work of managing a condition can wear you down. It's not weakness — it's a normal response to a heavy load, and it's very treatable." },
  { id: 719, category: 'depression', keywords: ['does depression make chronic illness worse'], question: "Can depression make my other health problems harder to manage?", response: "Yes — when you're depressed it's harder to remember medicines, go to appointments, eat well, or stay active. That can make the original condition feel even tougher. Treating the depression often makes everything else a little easier." },
  { id: 720, category: 'depression', keywords: ['talking to doctor about depression and illness'], question: "Should I tell my doctors I'm depressed even if I'm seeing them for something else?", response: "Absolutely. Tell every doctor and nurse about your depression so they can choose treatments that are safe with your other conditions. Good communication helps everyone take the best care of you." },
  { id: 721, category: 'treatment', keywords: ['treating depression with chronic illness'], question: "How is depression treated when you have other medical problems?", response: "The same main tools — counseling and antidepressants — are used, but your doctor picks options that are safe with your other conditions. You don't have to choose between treating one or the other." },
  { id: 722, category: 'safety', keywords: ['depression and heart disease'], question: "Is depression common after a heart problem?", response: "Yes — many people feel depressed after a heart attack, stent, or heart failure diagnosis. The stress and physical changes can trigger it. Treating the depression is important because it can affect how well your heart recovers." },
  { id: 723, category: 'safety', keywords: ['depression and diabetes'], question: "Does depression affect diabetes?", response: "It can. Depression can make it harder to check blood sugar, take insulin, or eat in a way that helps diabetes. Getting support for the depression often makes diabetes management feel less overwhelming." },
  { id: 724, category: 'safety', keywords: ['depression and cancer'], question: "Is depression common during or after cancer treatment?", response: "Very common. The fear, fatigue, pain, and life changes that come with cancer can bring on depression. Many cancer centers now screen for it and offer support — you're not alone in this." },
  { id: 725, category: 'safety', keywords: ['depression and chronic pain'], question: "Can chronic pain and depression go together?", response: "They often do. Pain makes depression worse, and depression makes pain feel stronger. Treating both at the same time usually gives the best relief." },
  { id: 726, category: 'treatment', keywords: ['support groups for chronic illness depression'], question: "Would a support group help if I have depression and another illness?", response: "Many women find them incredibly helpful. Hearing others in the same situation share what works can make you feel less alone and give you practical ideas you can try." },
  { id: 727, category: 'safety', keywords: ['depression and stroke'], question: "Is depression common after a stroke?", response: "Yes — it's very common after a stroke. The brain changes, physical limitations, and fear can all contribute. Treating the depression is an important part of stroke recovery." },
  { id: 728, category: 'safety', keywords: ['depression and COPD'], question: "Does depression affect breathing problems like COPD?", response: "It can. Depression can make it harder to stay active, take medicines on time, or do breathing exercises. Getting support for the mood side often helps people manage their lung condition better." },
  { id: 729, category: 'safety', keywords: ['depression and obesity'], question: "Can depression and weight be connected?", response: "They often are. Depression can affect appetite, energy, and motivation to move, and carrying extra weight can sometimes worsen mood. Treating one can make the other feel more manageable." },
  { id: 730, category: 'safety', keywords: ['depression and Parkinson disease'], question: "Is depression common with Parkinson's?", response: "Yes — it's very common. The same brain changes that cause Parkinson's can also affect mood. Treating the depression is an important part of caring for the whole person." },
  { id: 731, category: 'depression', keywords: ['dont assume depression is normal with illness'], question: "Is feeling depressed just a normal part of being sick?", response: "It's normal to feel sad or worried when you're dealing with a health problem, but depression is more than that. If it's lasting and making life harder, it's worth treating — you don't have to just live with it." },
  { id: 732, category: 'safety', keywords: ['talking to all doctors about depression'], question: "Why is it important that all my doctors know about my depression?", response: "Because some medicines for other conditions can interact with antidepressants, and some treatments for depression need to be chosen carefully when you have heart, liver, kidney, or other problems. Full information keeps you safe." },

  // === Persistent Depressive Disorder (IDs 733–748) ===
  { id: 733, category: 'depression', keywords: ['persistent depressive disorder', 'pdd', 'dysthymia'], question: "What is persistent depressive disorder (PDD)?", response: "PDD (formerly called dysthymia) is a long-lasting, lower-grade form of depression that continues for two years or more. The sadness or irritability is there most days, but it might not feel as intense as a full major depressive episode. It can still make life feel heavy and tiring." },
  { id: 734, category: 'depression', keywords: ['pdd symptoms', 'symptoms of persistent depression'], question: "What are the main symptoms of PDD?", response: "You feel down or irritable most of the day, almost every day, for at least two years. You also have at least two of these: changes in appetite or sleep, low energy, low self-esteem, trouble concentrating or making decisions, or feeling hopeless." },
  { id: 735, category: 'depression', keywords: ['pdd vs major depression', 'double depression'], question: "What's the difference between PDD and major depression?", response: "PDD is the long, steady, lower-level sadness that lasts years. Major depression is more intense but usually shorter episodes. Some people have both at the same time — that's called 'double depression' and can feel especially exhausting." },
  { id: 736, category: 'depression', keywords: ['how is pdd diagnosed'], question: "How do doctors diagnose PDD?", response: "They ask about how long your low mood has lasted (at least two years) and whether you've had no more than two months symptom-free in that time. They'll also check that the symptoms are causing real problems in your daily life." },
  { id: 737, category: 'treatment', keywords: ['treatment for pdd', 'how to treat persistent depression'], question: "How is PDD treated?", response: "The most effective approach is usually a combination of counseling (like CBT) and antidepressant medicine. Many women feel noticeably better when both are used together. Your doctor will work with you to find the right balance." },
  { id: 738, category: 'treatment', keywords: ['pdd and pmdd overlap'], question: "Can someone have both PDD and PMDD?", response: "Yes — some women have the steady low mood of PDD and then get extra-intense symptoms in the luteal phase (PMDD). Tracking your cycle alongside your overall mood helps your doctor see the full picture." },
  { id: 739, category: 'treatment', keywords: ['self help for pdd'], question: "What can I do on my own to help with PDD?", response: "Stick to regular sleep, gentle exercise, healthy meals, and avoid alcohol and recreational drugs. Reach out to supportive people and try simple stress-reduction practices like deep breathing or short walks. Small, steady habits really add up." },
  { id: 740, category: 'safety', keywords: ['pdd and suicidal thoughts'], question: "Is there a higher risk of suicidal thoughts with PDD?", response: "Yes, even though the depression feels more chronic than acute, the risk is real. If you ever feel life isn't worth living, please reach out right away — call or text 988, talk to your doctor, or go to the ER." },
  { id: 741, category: 'treatment', keywords: ['how long does pdd treatment take'], question: "How long does it take to feel better from PDD?", response: "Because PDD has been going on for a long time, improvement can take a few months of consistent treatment. Most women start noticing benefits within 4–8 weeks of starting medicine or therapy, but the full effect can take longer." },
  { id: 742, category: 'treatment', keywords: ['pdd and relationships'], question: "Does PDD affect relationships?", response: "It can. The ongoing low mood and low energy can make it harder to connect with partners, friends, or family. Treatment often helps you feel more present and engaged again." },
  { id: 743, category: 'treatment', keywords: ['pdd and work school'], question: "Can PDD affect work or school?", response: "Yes — trouble concentrating, low energy, and feeling hopeless can make it hard to perform or keep up. Getting effective treatment usually helps you feel more capable again." },
  { id: 744, category: 'safety', keywords: ['pdd and alcohol'], question: "Should I avoid alcohol with PDD?", response: "It's usually best to limit or avoid alcohol. It can make depression symptoms feel heavier and can also interfere with how well your medicine works." },
  { id: 745, category: 'treatment', keywords: ['pdd and exercise'], question: "Does exercise help PDD?", response: "Yes — even gentle, regular movement can lift mood and energy over time. Start small and build up at your own pace. Consistency matters more than intensity." },
  { id: 746, category: 'treatment', keywords: ['pdd and sleep'], question: "Why is sleep so important with PDD?", response: "Poor sleep makes the low mood and fatigue worse. Aiming for a consistent 7–9 hours and a calm bedtime routine can make a noticeable difference in how you feel." },
  { id: 747, category: 'treatment', keywords: ['pdd and support'], question: "Is it helpful to talk to others about PDD?", response: "Absolutely. Sharing with trusted friends, family, or a support group can make you feel less alone and give you practical ideas. You don't have to carry this by yourself." },
  { id: 748, category: 'depression', keywords: ['pdd long term outlook'], question: "Will PDD ever go away?", response: "With the right treatment many women see major improvement and some reach full remission. Even if it's been going on for years, it's never too late to start feeling better. Your doctor can help you create a plan that works for the long term." },

  // === Anxiety & GAD (IDs 813–828) ===
  { id: 813, category: 'anxiety', keywords: ['normal anxiety vs anxiety disorder', 'when is anxiety a problem'], question: "When is anxiety a real medical problem?", response: "Everyone feels anxious sometimes — that's normal. But when worry or fear is intense, happens most days for 6 months or longer, and starts getting in the way of your work, relationships, or daily life, it may be generalized anxiety disorder (GAD) or another anxiety condition. You don't have to just live with it." },
  { id: 814, category: 'anxiety', keywords: ['symptoms of severe anxiety', 'generalized anxiety disorder symptoms'], question: "What are the main symptoms of severe anxiety or GAD?", response: "You might feel constantly on edge, worried about many things (even small ones), or unable to relax. Other common signs include trouble sleeping, difficulty concentrating, feeling very tired, tense muscles, stomach issues, or chest tightness." },
  { id: 815, category: 'anxiety', keywords: ['anxiety and pmdd', 'anxiety during luteal phase'], question: "Can PMDD make anxiety worse?", response: "Yes — many women notice their anxiety ramps up significantly in the luteal phase. The hormonal shifts can intensify worry, restlessness, and physical tension. Tracking both your cycle and anxiety symptoms helps show the pattern clearly." },
  { id: 816, category: 'anxiety', keywords: ['how is anxiety diagnosed'], question: "How do doctors diagnose anxiety disorders?", response: "They ask about your symptoms, how long they've been going on, and how much they're affecting your daily life. Sometimes they use short questionnaires to screen for anxiety. If needed, they may do basic tests to rule out other medical causes." },
  { id: 817, category: 'treatment', keywords: ['therapy for anxiety', 'counseling for anxiety'], question: "Does therapy help with anxiety?", response: "Yes — therapy (especially CBT) is one of the most effective treatments. It helps you notice unhelpful worry patterns, learn new ways of thinking, and build practical skills to manage anxiety. Many women feel much steadier with the right therapist." },
  { id: 818, category: 'treatment', keywords: ['medication for anxiety', 'antidepressants for anxiety'], question: "Do medicines help with anxiety?", response: "Yes — many of the same medicines used for depression (especially SSRIs and SNRIs) are also very effective for anxiety, even if you're not depressed. Your doctor will help choose one that fits your symptoms and any other health needs." },
  { id: 819, category: 'treatment', keywords: ['therapy vs medication for anxiety'], question: "Should I do therapy, medicine, or both for anxiety?", response: "Many women do best with both together. Therapy gives you lasting skills, while medicine can help lower the intensity of worry so you can use those skills more easily. Your doctor will help you decide what feels right for you." },
  { id: 820, category: 'self_help', keywords: ['self help for anxiety', 'things that help anxiety'], question: "What can I do on my own to help my anxiety?", response: "Regular gentle movement, cutting back on caffeine, good sleep habits, and simple mindfulness or breathing practices can make a real difference. Many women also find yoga, tai chi, or short daily meditation helpful." },
  { id: 821, category: 'self_help', keywords: ['exercise for anxiety'], question: "Does exercise help with anxiety?", response: "It really can. Even a regular walk or gentle movement helps burn off nervous energy and improves mood. You don't have to do anything intense — consistency matters more than intensity." },
  { id: 822, category: 'self_help', keywords: ['caffeine and anxiety'], question: "Does caffeine make anxiety worse?", response: "It often does. Cutting back (or stopping) coffee, tea, energy drinks, and chocolate can noticeably reduce jitteriness and worry for many women, especially in the luteal phase." },
  { id: 823, category: 'self_help', keywords: ['sleep and anxiety'], question: "How does sleep affect anxiety?", response: "Poor sleep makes anxiety much worse, and anxiety makes it harder to sleep. Protecting a consistent bedtime routine and aiming for 7–9 hours can create a helpful cycle the other way." },
  { id: 824, category: 'safety', keywords: ['anxiety and pregnancy'], question: "Can I treat anxiety while pregnant or trying to conceive?", response: "Yes — but some medicines are safer than others. Talk with your doctor before trying to get pregnant or as soon as you know you're pregnant so you can make the safest plan for you and your baby." },
  { id: 825, category: 'treatment', keywords: ['how long does anxiety treatment take'], question: "How long until I feel better from anxiety treatment?", response: "Many women notice some improvement within a few weeks of starting therapy or medicine, but the biggest changes often come after 6–12 weeks of consistent treatment. Be patient with yourself." },
  { id: 826, category: 'safety', keywords: ['when to get help for anxiety'], question: "When should I talk to a doctor about my anxiety?", response: "If worry or fear is intense, happening most days, lasting more than a few weeks, or getting in the way of work, school, or relationships, it's worth getting checked. You don't have to wait until it feels unbearable." },
  { id: 827, category: 'safety', keywords: ['anxiety and physical symptoms'], question: "Can anxiety cause real physical symptoms?", response: "Yes — tight muscles, stomach issues, chest tightness, fatigue, and trouble sleeping are all very common. These symptoms are real, even though they're driven by anxiety. Treating the anxiety usually helps the physical side too." },
  { id: 828, category: 'treatment', keywords: ['finding the right anxiety treatment'], question: "What if the first treatment for anxiety doesn't help?", response: "That's common. Many women need to try a couple of approaches (different therapy styles, different medicines, or adding lifestyle changes) before they find what works best. Don't give up — your doctor can adjust the plan with you." },

  // === Exercise & Movement (IDs 829–844) ===
  { id: 829, category: 'self_help', keywords: ['benefits of exercise', 'why movement helps'], question: "What are the real benefits of moving my body?", response: "Movement helps in so many ways — it can lift your mood, lower stress and anxiety, help with sleep, keep your bones stronger, and support your heart. Even small amounts of regular movement make a meaningful difference over time." },
  { id: 830, category: 'self_help', keywords: ['exercise for depression and anxiety'], question: "Can exercise really help with depression or anxiety?", response: "Yes — regular movement is one of the most evidence-based ways to support mood. It can reduce anxiety, ease depressive symptoms, and give you more steady energy. You don't have to do anything intense for it to help." },
  { id: 831, category: 'self_help', keywords: ['types of exercise', 'aerobic vs strength training'], question: "What are the main types of exercise I should do?", response: "There are three helpful types: aerobic movement (walking, dancing, swimming) that raises your heart rate, strength training (using your body weight, bands, or weights) to keep muscles and bones strong, and stretching to stay flexible and comfortable in your body." },
  { id: 832, category: 'self_help', keywords: ['how often should I exercise'], question: "How much exercise do I actually need?", response: "Most people benefit from moving at least 30 minutes on 5 or more days a week. If that feels like too much at once, you can break it into shorter sessions — even 10 minutes a few times a day adds up and still helps." },
  { id: 833, category: 'self_help', keywords: ['starting exercise when tired or busy'], question: "What if I'm too tired or busy to exercise?", response: "That's really common. Start with very small amounts of movement and build from there. Even short walks, stretching, or moving around during the day can improve how you feel. Consistency matters more than long workouts." },
  { id: 834, category: 'self_help', keywords: ['reducing sitting time', 'movement throughout the day'], question: "What if I sit a lot for work?", response: "Try to stand up and move for a few minutes every 30–60 minutes. You can also take the stairs, park farther away, or do short walks during the day. These small movements really add up for your health and mood." },
  { id: 835, category: 'self_help', keywords: ['how to structure a workout', 'warm up cool down'], question: "How should I structure my movement time?", response: "A simple, effective session has three parts: a 5–10 minute warm-up (light movement + stretching), the main workout (aerobic + strength moves), and a 5-minute cooldown (slow movement + stretching). This helps your body feel better before and after." },
  { id: 836, category: 'self_help', keywords: ['exercise safety tips'], question: "How can I exercise safely?", response: "Start slowly, stay hydrated, wear comfortable supportive shoes, and listen to your body. If something doesn't feel right, slow down or stop. You can always build up over time — there's no rush." },
  { id: 837, category: 'self_help', keywords: ['when to talk to doctor before exercising'], question: "Should I check with my doctor before starting to exercise?", response: "It's a good idea if you haven't been active in a while, or if you have heart disease, diabetes, or other ongoing health conditions. Your doctor can help you choose what's safest and most helpful for your body." },
  { id: 838, category: 'self_help', keywords: ['exercise and PMDD', 'movement during luteal phase'], question: "Does exercise help with PMDD symptoms?", response: "Many women find that gentle, consistent movement (especially walking or light strength work) can ease mood symptoms, bloating, and fatigue during the luteal phase. Listen to your body — some days you may need gentler movement than others." },
  { id: 839, category: 'self_help', keywords: ['exercise when depressed'], question: "How do I start moving when I feel too depressed to exercise?", response: "Start tiny. Even a 5–10 minute walk or some gentle stretching counts. The hardest part is often just beginning. Many women notice they feel a little lighter afterward, even if they didn't feel motivated at first." },
  { id: 840, category: 'self_help', keywords: ['best exercise for beginners'], question: "What's the easiest way to start moving more?", response: "Walking is one of the simplest and most effective places to begin. You can do it anywhere, it doesn't require equipment, and you can start with just a few minutes. Over time you can gradually walk longer or add other activities you enjoy." },
  { id: 841, category: 'self_help', keywords: ['exercise and motivation'], question: "How do I stay motivated to keep moving?", response: "Find movement you actually enjoy (or at least don't hate), do it with a friend when possible, and celebrate small wins. You don't have to love every session — showing up consistently is what matters most." },
  { id: 842, category: 'safety', keywords: ['when to stop exercising'], question: "When should I stop exercising and call my doctor?", response: "Stop and get help right away if you feel chest pain or pressure, sudden dizziness, nausea, a very fast or irregular heartbeat, or anything that feels seriously wrong. It's always okay to pause and check in with your body." },
  { id: 843, category: 'self_help', keywords: ['exercise and mental health'], question: "How does movement help my mental health?", response: "Regular movement can lower stress and anxiety, lift mood, improve sleep, and give you a sense of accomplishment. It's one of the most powerful daily tools many women have for feeling steadier, especially during harder luteal phases." },
  { id: 844, category: 'self_help', keywords: ['gentle movement ideas'], question: "What if I don't like intense exercise?", response: "You don't have to do anything intense. Gentle walking, stretching, yoga, dancing in your kitchen, or even gardening all count. The goal is simply to move your body more than you were before — every bit helps." },

  // === Worry, Stress & Coping (IDs 845–860) ===
  { id: 845, category: 'anxiety', keywords: ['what is worry', 'normal worry vs problem worry'], question: "What's the difference between normal worry and a problem?", response: "A little worry is normal and can even be helpful — it keeps us careful and can push us to solve problems. But when worry is intense, happens most days, and starts interfering with your sleep, work, relationships, or daily life, it's worth paying attention to and getting support for." },
  { id: 846, category: 'anxiety', keywords: ['what is stress', 'acute vs chronic stress'], question: "What's the difference between short-term and long-term stress?", response: "Short-term (acute) stress is normal and can even be helpful — it gives you energy to handle a challenge and then fades. Long-term (chronic) stress that goes on for weeks or months is harder on your body and mind and is more likely to affect your health and mood." },
  { id: 847, category: 'anxiety', keywords: ['coping with worry and stress'], question: "How can I cope better with worry and stress?", response: "Start by noticing what's causing it. Then focus on what you can control — your thoughts, small actions, and environment. Writing things down, deciding what really matters, saying no to extra demands, and making time for rest can all help lighten the load." },
  { id: 848, category: 'self_help', keywords: ['healthy ways to manage stress'], question: "What are some healthy ways to handle stress?", response: "Move your body (even a short walk), eat nourishing food, limit caffeine, protect your sleep, and reach out to people you trust. Doing something kind for someone else or spending a few minutes on a hobby you enjoy can also give your mind a helpful break." },
  { id: 849, category: 'self_help', keywords: ['deep breathing for anxiety'], question: "How can deep breathing help with worry or stress?", response: "Slow, deep breaths (in through the nose, hold for a few seconds, out through the mouth) can calm your nervous system quickly. It's a simple tool you can use anywhere when worry or stress starts to feel overwhelming." },
  { id: 850, category: 'self_help', keywords: ['progressive muscle relaxation'], question: "What is progressive muscle relaxation?", response: "It's a technique where you gently tense and then release different muscle groups one by one. It helps your body recognize the difference between tension and relaxation and can ease both physical and mental stress." },
  { id: 851, category: 'self_help', keywords: ['guided visualization for stress'], question: "How does guided visualization help with stress?", response: "You close your eyes and picture a calm, safe place in detail (sounds, smells, temperature, colors). It gives your mind a break from worry and can lower stress in just a few minutes." },
  { id: 852, category: 'self_help', keywords: ['mindfulness for anxiety'], question: "What is mindfulness and how does it help with worry?", response: "Mindfulness is gently bringing your attention to the present moment instead of getting lost in worries about the future or past. It can be practiced through meditation, walking, or even everyday activities and often makes anxious thoughts feel less overwhelming." },
  { id: 853, category: 'self_help', keywords: ['yoga tai chi for stress'], question: "Can yoga or tai chi help with stress and anxiety?", response: "Yes — both combine gentle movement with breathing and focus. They can calm the mind, reduce physical tension, and improve how you feel overall. Even short sessions a few times a week can make a noticeable difference." },
  { id: 854, category: 'self_help', keywords: ['sleep and stress'], question: "How does sleep affect stress and worry?", response: "Poor sleep makes stress and anxiety feel much worse, and stress makes it harder to sleep well. Protecting a consistent bedtime routine and aiming for enough rest is one of the most helpful things you can do for your mental health." },
  { id: 855, category: 'self_help', keywords: ['caffeine and anxiety stress'], question: "Does caffeine make anxiety or stress worse?", response: "It often does. Cutting back on coffee, tea, energy drinks, and chocolate can reduce jitteriness and make it easier to feel calmer, especially if you're already dealing with a lot of worry." },
  { id: 856, category: 'self_help', keywords: ['writing down worries'], question: "Does writing down my worries help?", response: "It really can. Putting your thoughts on paper can help you see them more clearly, decide what's actually important, and sometimes let them go. Many women find it especially useful before bed so their mind can rest." },
  { id: 857, category: 'self_help', keywords: ['saying no to reduce stress'], question: "How does learning to say no help with stress?", response: "It protects your time and energy. When you're already stretched thin, saying no to things that aren't essential (or that add more pressure) can lower your overall stress load and give you room to breathe." },
  { id: 858, category: 'treatment', keywords: ['when to get help for anxiety or stress'], question: "When should I talk to a doctor about my worry or stress?", response: "If worry or stress is intense, happening most days, lasting a long time, or getting in the way of sleep, work, or relationships, it's worth getting support. You don't have to wait until it feels unbearable — early help often makes things easier." },
  { id: 859, category: 'treatment', keywords: ['therapy for anxiety and stress'], question: "Can therapy help with worry and stress?", response: "Yes — therapy (especially CBT) can help you understand your worry patterns, build practical coping skills, and feel more in control. Many women find it life-changing when combined with small daily habits that support their nervous system." },
  { id: 860, category: 'self_help', keywords: ['small steps for stress management'], question: "What if everything feels overwhelming right now?", response: "Start with one tiny thing — a few deep breaths, a short walk, writing down one worry, or texting a supportive person. You don't have to fix everything at once. Small, kind steps add up and can help you feel a little steadier." },

  // === Hormonal Birth Control (IDs 861–876) ===
  { id: 861, category: 'birth_control', keywords: ['what is hormonal birth control', 'types of hormonal contraception'], question: "What is hormonal birth control?", response: "Hormonal birth control uses hormones (estrogen and/or progestin) to prevent pregnancy. It comes in many forms — daily pills, weekly patches, monthly rings, injections every 3 months, arm implants, and hormonal IUDs. All are very effective when used correctly, though none protect against STIs." },
  { id: 862, category: 'birth_control', keywords: ['birth control pill options'], question: "What are the different types of birth control pills?", response: "There are combination pills (estrogen + progestin) and progestin-only pills. Most packs include 4–7 hormone-free days when you get your period. Some women use 'continuous dosing' by skipping the placebo pills to avoid having a period." },
  { id: 863, category: 'birth_control', keywords: ['birth control patch'], question: "How does the birth control patch work?", response: "You wear a small patch on your skin (shoulder, back, belly, or upper arm) that releases estrogen and progestin. You change it once a week for 3 weeks, then go patch-free for the 4th week when you get your period." },
  { id: 864, category: 'birth_control', keywords: ['vaginal ring birth control'], question: "How does the vaginal ring work?", response: "It's a flexible ring you insert into your vagina that releases estrogen and progestin. You typically leave it in for 3 weeks, then remove it for 1 week to have your period. Some rings can stay in longer if you want to skip periods." },
  { id: 865, category: 'birth_control', keywords: ['depo provera shot'], question: "What is the birth control injection?", response: "It's a shot (Depo-Provera) that contains only progestin. You get it every 3 months in the arm or buttock. It's very effective but can cause irregular bleeding or changes in periods for some people." },
  { id: 866, category: 'birth_control', keywords: ['nexplanon implant'], question: "What is the birth control implant?", response: "It's a tiny flexible rod placed under the skin of your upper arm that releases progestin. It can stay in for up to 5 years and is one of the most effective methods available. It's a great 'set it and forget it' option." },
  { id: 867, category: 'birth_control', keywords: ['hormonal IUD'], question: "How does a hormonal IUD work?", response: "It's a small T-shaped device placed in your uterus that releases a progestin called levonorgestrel. Depending on the brand and your age, it can last 3 to 8 years. Many women have much lighter periods or stop having periods altogether while using one." },
  { id: 868, category: 'birth_control', keywords: ['benefits of hormonal birth control'], question: "What are the benefits of hormonal birth control besides preventing pregnancy?", response: "It can make periods lighter, more regular, and less painful. It's often used to help with heavy bleeding, PCOS symptoms, menstrual migraines (without aura), and endometriosis pain. Many women choose it for these benefits even when pregnancy prevention isn't the main goal." },
  { id: 869, category: 'birth_control', keywords: ['choosing hormonal birth control'], question: "How do I choose the right hormonal birth control for me?", response: "Think about how easy it will be for you to use correctly every day or month. Long-acting methods (IUD or implant) are the most convenient. Also consider how each method might affect your periods, any side effects you want to avoid, and your overall health." },
  { id: 870, category: 'birth_control', keywords: ['who should not use estrogen birth control'], question: "Who should not use birth control that contains estrogen?", response: "Estrogen-containing methods are usually not recommended if you're over 35 and smoke, have a history of blood clots or stroke, certain types of breast cancer, some heart or liver conditions, or migraines with aura. Progestin-only options are often safer in these situations." },
  { id: 871, category: 'birth_control', keywords: ['birth control drug interactions'], question: "Do other medicines affect hormonal birth control?", response: "Yes — some seizure medicines, rifampin (for tuberculosis), and St. John's Wort can make hormonal birth control less effective. Always tell your doctor or pharmacist that you're using hormonal birth control when starting any new medicine." },
  { id: 872, category: 'birth_control', keywords: ['forgot birth control what to do'], question: "What should I do if I forget my birth control?", response: "Use emergency contraception as soon as possible. Options include the copper IUD (most effective), ella, or Plan B (available over the counter). The sooner you take it after unprotected sex, the better it works." },
  { id: 873, category: 'birth_control', keywords: ['hormonal birth control and PMDD'], question: "Can hormonal birth control help with PMDD?", response: "For some women, continuous or extended-cycle hormonal birth control can reduce or eliminate the hormonal fluctuations that trigger PMDD symptoms. It's not right for everyone, but it's one option worth discussing with your doctor if PMDD is significantly affecting your life." },
  { id: 874, category: 'birth_control', keywords: ['hormonal IUD for heavy periods'], question: "Can a hormonal IUD help with heavy or painful periods?", response: "Yes — hormonal IUDs often make periods much lighter or stop them completely after a few months. Many women with heavy bleeding or painful periods find significant relief. It's one of the most effective non-surgical treatments for heavy menstrual bleeding." },
  { id: 875, category: 'birth_control', keywords: ['starting hormonal birth control'], question: "How do I get started on hormonal birth control?", response: "Talk with your doctor or nurse. They'll review your health history, discuss your options, and help you choose the method that best fits your life and preferences. You can usually start most methods right away, even on the day of your visit." },
  { id: 876, category: 'birth_control', keywords: ['hormonal birth control safety'], question: "Is hormonal birth control safe?", response: "For most healthy women, yes — it's very safe and well studied. Your doctor will review your personal health history to make sure it's a good fit. There are many options, so if one method doesn't work well for you, there are usually good alternatives." },

  // === Menstruation Basics (IDs 877–892) ===
  { id: 877, category: 'menstruation', keywords: ['what is menstruation', 'what is a period'], question: "What is menstruation?", response: "Menstruation (having your period) is when the lining of the uterus sheds and comes out through the vagina as blood and tissue. It's a normal, healthy part of having a uterus and usually starts during puberty and continues until menopause." },
  { id: 878, category: 'menstruation', keywords: ['why do periods happen', 'menstrual cycle hormones'], question: "Why does menstruation happen?", response: "Each cycle, hormones cause the lining of the uterus to thicken in preparation for a possible pregnancy. If no pregnancy occurs, the body releases the lining as your period. This cycle usually repeats about once a month and is driven by the rise and fall of estrogen and progesterone." },
  { id: 879, category: 'menstruation', keywords: ['normal period cycle length'], question: "How often should I get my period?", response: "A normal cycle ranges from about 24 to 38 days, counted from the first day of one period to the first day of the next. Most people bleed for a few days up to about a week. It's common for cycles to be irregular when you first start getting periods or as you approach menopause." },
  { id: 880, category: 'menstruation', keywords: ['common period symptoms', 'PMS symptoms'], question: "What symptoms can come with my period?", response: "Many women experience bloating, breast tenderness, cramps, fatigue, headaches, mood changes, acne, or changes in appetite or sleep. These are related to hormone shifts and can start even before bleeding begins. For some, these symptoms are mild; for others they're more intense." },
  { id: 881, category: 'menstruation', keywords: ['PMS vs PMDD menstruation'], question: "What's the difference between PMS and PMDD?", response: "PMS involves symptoms like mood changes, bloating, and cramps that happen in the days before your period. PMDD is a more severe form where mood symptoms (irritability, anxiety, depression) are intense enough to significantly disrupt daily life. PMDD often needs medical treatment." },
  { id: 882, category: 'menstruation', keywords: ['ovulation pain', 'mittelschmerz'], question: "Can I feel ovulation?", response: "Some women feel a brief pain or twinge on one side of the lower belly around ovulation (usually about 14 days before the next period). This is called mittelschmerz. It's usually harmless but worth tracking if it's strong or one-sided." },
  { id: 883, category: 'menstruation', keywords: ['what affects my period', 'irregular periods causes'], question: "What can make my period irregular or stop?", response: "Stress, big changes in weight or exercise, pregnancy, breastfeeding, certain health conditions (like PCOS), and some medicines can all affect your cycle. If your periods suddenly become very irregular or stop for more than a few months without an obvious reason, it's worth checking with your doctor." },
  { id: 884, category: 'products', keywords: ['types of period products', 'pads vs tampons vs cup'], question: "What are the different types of menstrual products?", response: "You can choose from pads (worn in underwear), tampons (inserted in the vagina), menstrual cups or discs (reusable and worn inside), and period underwear. Many women use a mix depending on their flow, activities, and comfort. Reusable options can be more sustainable and cost-effective over time." },
  { id: 885, category: 'products', keywords: ['how to use tampons safely'], question: "How often should I change a tampon?", response: "Change tampons every 4 to 8 hours. Leaving one in too long increases the risk of toxic shock syndrome, a rare but serious infection. Always use the lowest absorbency that works for your flow and never leave one in overnight." },
  { id: 886, category: 'self_care', keywords: ['period cramps relief', 'how to ease period pain'], question: "What helps with period cramps?", response: "Over-the-counter NSAIDs like ibuprofen or naproxen are often very effective. A heating pad on low, gentle movement, staying hydrated, and eating smaller, less salty meals can also help. Some women find relief with magnesium, acupuncture, or certain types of hormonal birth control." },
  { id: 887, category: 'self_care', keywords: ['period bloating relief'], question: "What helps with period bloating?", response: "Reducing salt, staying hydrated, gentle movement, and wearing loose clothing can ease bloating. Some women also find that certain hormonal birth control methods reduce bloating over time. If bloating is severe, it's worth discussing with your doctor." },
  { id: 888, category: 'self_care', keywords: ['exercising on your period'], question: "Can I exercise during my period?", response: "Yes — gentle to moderate movement (walking, yoga, swimming, light strength training) can actually help reduce cramps, bloating, and low mood for many women. Listen to your body and adjust intensity as needed." },
  { id: 889, category: 'self_care', keywords: ['period self care tips'], question: "How can I take better care of myself during my period?", response: "Prioritize rest when you need it, stay hydrated, eat nourishing foods, use heat for cramps, and be kind to yourself if your energy or mood is lower. Tracking your cycle can also help you plan ahead for days when you might need extra support." },
  { id: 890, category: 'menstruation', keywords: ['when to see doctor about periods'], question: "When should I talk to a doctor about my periods?", response: "See a doctor if you haven't started periods by age 15–16, if periods suddenly become very irregular or stop, if you soak through a pad or tampon every 1–2 hours, pass large clots, have very painful cramps that don't improve with medicine, or have any other symptoms that worry you." },
  { id: 891, category: 'menstruation', keywords: ['period tracking why'], question: "Why is it helpful to track my period?", response: "Tracking helps you notice patterns in your cycle, symptoms, mood, and energy. It can alert you early to changes that might need medical attention and helps you plan for symptoms. Apps or a simple calendar both work well." },
  { id: 892, category: 'menstruation', keywords: ['period products for heavy flow'], question: "What products work best for a heavy period?", response: "Many women with heavy flow use super-absorbency tampons or pads, a menstrual cup (which can hold more), or period underwear as backup. Layering products (cup + period underwear) can give extra peace of mind. If your flow is very heavy, talk to your doctor — there are effective treatments available." },

  // === PMS & PMDD Overview (IDs 893–908) ===
  { id: 893, category: 'pmdd', keywords: ['pms vs pmdd clinical overview'], question: "What's the difference between PMS and PMDD (clinical overview)?", response: "PMS involves annoying physical and mood symptoms in the week or two before your period. PMDD is the more intense version — the mood symptoms (irritability, anger, sadness, anxiety, feeling out of control) become severe enough to seriously disrupt work, relationships, or daily life. Both improve once your period starts." },
  { id: 894, category: 'pmdd', keywords: ['how common is pmdd clinical'], question: "How common is PMDD (clinical data)?", response: "Mild PMS is very common (up to 75% of women). True PMDD affects about 3–8% of women. It's a real medical condition, not something you're making up or exaggerating." },
  { id: 895, category: 'pmdd', keywords: ['why do some women get pmdd brain sensitivity clinical'], question: "Why do some women get PMDD and others don't (clinical)?", response: "Most women with PMDD have normal hormone levels. The current understanding is that their brains are more sensitive to the normal ups and downs of estrogen and progesterone across the cycle, especially how those changes affect serotonin." },
  { id: 896, category: 'pmdd', keywords: ['common pmdd symptoms hallmark'], question: "What are the most common symptoms of PMDD?", response: "The hallmark symptoms are intense mood changes in the luteal phase: irritability or anger, feeling on edge or anxious, deep sadness or hopelessness, mood swings, and feeling overwhelmed. Many women also get physical symptoms like bloating, breast tenderness, fatigue, and trouble sleeping or concentrating." },
  { id: 897, category: 'pmdd', keywords: ['pmdd vs depression clinical how to tell'], question: "How is PMDD different from regular depression or anxiety?", response: "In PMDD the symptoms are tightly tied to the luteal phase and mostly disappear once your period starts. With regular depression or anxiety, symptoms are usually present all month long (even if they get worse before your period). Tracking for two cycles helps tell them apart clearly." },
  { id: 898, category: 'pmdd', keywords: ['pmdd diagnosis clinical process'], question: "How do doctors diagnose PMDD?", response: "There's no blood test. The key is tracking your symptoms daily for at least two full cycles. If you see a clear pattern — significant mood and physical symptoms only in the luteal phase that lift with your period — that confirms PMDD. Your doctor will also rule out other conditions." },
  { id: 899, category: 'pmdd', keywords: ['pmdd symptom tracking two cycles why'], question: "Why do I need to track symptoms for two cycles?", response: "Tracking shows whether your symptoms are truly cycle-related or present all month. It's the most important step in getting an accurate diagnosis and helps your doctor choose the best treatment for you." },
  { id: 900, category: 'treatment', keywords: ['pmdd treatment options clinical'], question: "What are the main treatments for PMDD?", response: "The most effective treatments are SSRIs (antidepressants), certain birth control pills, and lifestyle changes. For severe cases that don't respond to other options, GnRH agonists with hormone add-back can be very helpful. Most women find significant relief with the right approach." },
  { id: 901, category: 'treatment', keywords: ['ssri for pmdd effectiveness'], question: "Are SSRIs effective for PMDD?", response: "Yes — SSRIs are one of the most effective treatments for PMDD. Between 60–75% of women improve significantly. They can be taken every day or only during the luteal phase. It usually takes 1–2 cycles to see the full benefit." },
  { id: 902, category: 'treatment', keywords: ['luteal phase ssri dosing clinical'], question: "Do I have to take an SSRI every day for PMDD?", response: "Not necessarily. Many women do well taking an SSRI only during the luteal phase (from ovulation until their period starts). This often means fewer side effects while still getting good symptom control. Your doctor can help decide which approach is best for you." },
  { id: 903, category: 'treatment', keywords: ['birth control for pmdd drospirenone clinical'], question: "Can birth control pills help PMDD?", response: "Some women get good relief from certain pills, especially those with drospirenone and a shorter hormone-free interval (like Yaz). Others find that the pill makes their symptoms worse. It's worth trying if you also want contraception, but it's not the first choice for everyone." },
  { id: 904, category: 'treatment', keywords: ['exercise and relaxation for pmdd clinical'], question: "Do exercise and relaxation help with PMDD?", response: "They can help reduce stress, tension, and low mood, and are good supportive treatments. However, for most women with PMDD they're not enough on their own. They work best alongside medication when symptoms are moderate to severe." },
  { id: 905, category: 'treatment', keywords: ['gnrh for severe pmdd clinical'], question: "When is GnRH agonist treatment used for PMDD?", response: "It's usually reserved for severe PMDD that hasn't responded to SSRIs or birth control. It temporarily turns off the ovaries and can be very effective, but it requires hormone add-back to protect bones and is typically used only when other options haven't worked well enough." },
  { id: 906, category: 'treatment', keywords: ['what doesnt work for pmdd clinical'], question: "What treatments don't help PMDD?", response: "Progesterone, most vitamins and supplements (including B6 and evening primrose oil), St. John's wort, and older antidepressants like tricyclics have not been shown to help PMDD. It's best to focus on treatments with good evidence, like SSRIs and certain hormonal options." },
  { id: 907, category: 'pmdd', keywords: ['pmdd impact on life clinical'], question: "How much does PMDD affect daily life?", response: "For women who have it, it can be significant — strained relationships, missed work or school, trouble concentrating, and feeling like you're not yourself for 1–2 weeks every month. The good news is that with the right treatment most women feel much more in control and like themselves again." },
  { id: 908, category: 'pmdd', keywords: ['hope for pmdd treatable'], question: "Is there hope if I have PMDD?", response: "Yes — PMDD is very treatable. Most women find meaningful relief with SSRIs, hormonal options, or a combination of approaches. It may take trying a couple of treatments to find what works best for you, but you don't have to just live with the intense symptoms every month." },

  // === Seasonal Affective Disorder (IDs 1069–1084) ===
  { id: 1069, category: 'depression', keywords: ['what is seasonal affective disorder', 'SAD definition'], question: "What is seasonal affective disorder (SAD)?", response: "Seasonal affective disorder is a subtype of depression where episodes of major depression regularly begin and end at the same time each year — most commonly starting in fall or winter and improving in spring or summer. The key feature is the predictable seasonal pattern, not just feeling a bit low in winter." },
  { id: 1070, category: 'depression', keywords: ['winter depression symptoms'], question: "What does winter depression (SAD) usually feel like?", response: "Winter depression often includes the usual signs of depression plus atypical features: sleeping more than usual (hypersomnia), craving carbohydrates, increased appetite, and weight gain. Many people also feel very low on energy, less social, and notice their mood lifts on sunny days or when they travel somewhere with more light." },
  { id: 1071, category: 'depression', keywords: ['how common is seasonal affective disorder'], question: "How common is seasonal affective disorder?", response: "In the general population, lifetime prevalence is roughly 0.5–3%. In primary care settings it's about 5–10%, and among people already being treated for depression it's around 15%." },
  { id: 1072, category: 'depression', keywords: ['why does SAD happen', 'causes of seasonal depression'], question: "What causes seasonal affective disorder?", response: "It's thought to involve changes in circadian rhythms due to shorter daylight in winter, reduced retinal sensitivity to light, shifts in serotonin and melatonin, and possibly genetic factors. The later sunrise in winter can delay your internal body clock relative to when you sleep, which contributes to low mood, fatigue, and sleep changes." },
  { id: 1073, category: 'depression', keywords: ['winter vs summer SAD'], question: "Is there a difference between winter and summer seasonal depression?", response: "Yes. Winter depression (much more common) tends to bring oversleeping, carbohydrate cravings, weight gain, and low energy. Summer depression is rarer and usually involves more typical depressive symptoms like insomnia and reduced appetite. Both follow a predictable seasonal pattern year after year." },
  { id: 1074, category: 'depression', keywords: ['how is SAD diagnosed'], question: "How do doctors diagnose seasonal affective disorder?", response: "Diagnosis requires a history of recurrent major depressive episodes that reliably start and stop at the same time of year (usually fall/winter onset and spring/summer remission) for at least the last two years, with no non-seasonal episodes in between." },
  { id: 1075, category: 'depression', keywords: ['SAD vs regular depression'], question: "How is seasonal affective disorder different from regular depression?", response: "The main difference is the clear, recurring seasonal timing. Both have the same core depressive symptoms, but SAD episodes predictably begin and end with the seasons. Winter SAD also tends to feature more hypersomnia, carbohydrate craving, and weight gain than typical non-seasonal depression." },
  { id: 1076, category: 'depression', keywords: ['does SAD go away on its own'], question: "Does seasonal depression eventually go away?", response: "Many people notice improvement in spring as daylight increases, but episodes can still be severe and impairing during winter. Over the long term, the strict seasonal pattern often fades for many people. Treatment can prevent or shorten episodes." },
  { id: 1077, category: 'depression', keywords: ['SAD and other mental health conditions'], question: "Do people with SAD often have other mental health issues?", response: "Yes. SAD commonly occurs alongside anxiety disorders, ADHD, eating disorders, and sometimes bipolar disorder. Having another condition can make symptoms feel more intense and may affect which treatments work best." },
  { id: 1078, category: 'depression', keywords: ['light therapy for SAD'], question: "Is light therapy effective for seasonal depression?", response: "Yes — bright light therapy is one of the most evidence-based treatments for winter SAD. It helps realign circadian rhythms and can improve mood, energy, and sleep within days to weeks for many people. It's often used daily in the morning during fall and winter." },
  { id: 1079, category: 'depression', keywords: ['how to tell if I have SAD'], question: "How can I tell if my winter low mood is actually SAD?", response: "Track whether your depressive symptoms reliably start in fall/winter and improve in spring/summer for at least two years, with no major non-seasonal episodes. Key clues include sleeping much more, strong carbohydrate cravings, weight gain, and feeling noticeably better on sunny days or when traveling to brighter locations." },
  { id: 1080, category: 'depression', keywords: ['SAD in perimenopause or hormonal changes'], question: "Can hormonal changes make seasonal depression worse?", response: "Yes — perimenopause and other hormonal shifts can intensify mood symptoms, sleep changes, and energy dips. If you already have a seasonal pattern, hormonal fluctuations may make winter episodes feel heavier. Tracking both your cycle and seasonal patterns can help clarify what's driving symptoms." },
  { id: 1081, category: 'depression', keywords: ['does moving affect SAD'], question: "If I move somewhere sunnier, will my seasonal depression go away?", response: "Many people notice significant improvement when they move to a location with more winter daylight or spend time in brighter climates. However, SAD can still occur in sunnier places for some individuals, especially if other factors are at play." },
  { id: 1082, category: 'depression', keywords: ['SAD and bipolar disorder'], question: "Can seasonal affective disorder occur with bipolar disorder?", response: "Yes. SAD can be a seasonal pattern of bipolar I or II disorder, not just unipolar depression. If you have a history of elevated mood, decreased need for sleep, or increased energy in certain seasons, it's important to get a full evaluation, as treatment approaches differ for bipolar depression." },
  { id: 1083, category: 'depression', keywords: ['long term outlook for SAD'], question: "What happens to seasonal affective disorder over many years?", response: "For many people the strict seasonal pattern becomes less consistent over time. Some continue having recurrent depression without the clear winter pattern, while others recover and have fewer episodes. Early recognition and treatment can reduce the impact and help prevent future episodes." },
  { id: 1084, category: 'depression', keywords: ['when to seek help for winter depression'], question: "When should I get help for feeling low every winter?", response: "If your mood, energy, sleep, or appetite change significantly every fall/winter and affect your work, relationships, or daily life, it's worth getting evaluated. Early support with light therapy, therapy, or medication can make winters much more manageable." },

];